  ('aboriginal-10ced7e2-moex-00356', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-111-3082b5f1', 'sub-aboriginal-10ced7e2-04', NULL, 'single_choice', '甲依規定注射疫苗因副作用而致健康嚴重受損，甲依法得主張何種請求權？', '["損失補償請求權", "國家賠償請求權", "民事賠償請求權", "結果除去請求權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:06+00:00", "source_pdf_sha1": "30267b12713c", "answer_pdf_sha1": "0d471d4816b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "503", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00357', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-110-b96fcbef', 'sub-aboriginal-10ced7e2-07', NULL, 'essay', '甲為 17 歲少年，尚未取得汽車駕照，某日深夜偷開父親乙（甲之法
定代理人）之車輛，載友人丙前往吃宵夜，行經快速道路（該路段
速限 70 公里/小時）時，甲以時速 150 公里狂飆直行，突然見遠處
右前方行駛於右側車道的丁，丁向左變換車道於甲之前方路徑，甲
煞車減速不及直接撞上丁駕駛之車輛左後方，丙死亡丁重傷，二車
嚴重毀損。據事後警方調查丁有依法顯示左方向燈，變換車道之時
速為 55 公里，試問：甲、乙、丙、丁之法律關係如何？甲應否為此
事故負責？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:06+00:00", "source_pdf_sha1": "b9ed62dd3773", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0805", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與刑法總則", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00358', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-110-b96fcbef', 'sub-aboriginal-10ced7e2-07', NULL, 'essay', '甲為 9 歲少年，在民國 108 年 11 月間，約一個星期期間內，透過
A 超商門市所設置之多媒體事務機（無任何「實名購買制」或「其
他可經審核行為能力之付款方式」），連續地與乙網路遊戲公司購
買網路遊戲之代幣，前後共計 11 次，每次金額為新臺幣（以下
同）70 元至 1400 元不等，總金額達 1 萬元整，並於購買後立即
將遊戲代幣使用完畢。嗣後，經甲之法定代理人丙發現甲之行為
並拒絕同意，此時遊戲帳戶餘額為 1（相當於 0.26 元）。然而乙公
司會員系統服務契約載明「若無行為能力人未由法定代理人代為
或限制行為能力人未經法定代理人同意而付費購買代幣，致生法
定代理人主張退費時，法定代理人得依本公司官網公告之退費流
程，備妥證明文件提出申請，經本公司確認後，將退還尚未使用
之遊戲代幣費用。」試問：甲乙之買賣契約有無效力？A 超商有
無責任？丙得請求乙公司退還多少款項？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:06+00:00", "source_pdf_sha1": "b9ed62dd3773", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0805", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與刑法總則", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00359', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-110-b96fcbef', 'sub-aboriginal-10ced7e2-07', NULL, 'essay', '甲為某關稅局服務之海關人員，負責貨物通關查驗、稽核等工作。
乙欲從國外違法走私電子煙進入臺灣，遂將大批電子煙藏匿在進口
水果的貨櫃中，想要魚目混珠，夾帶入境。乙得知甲為該批進口水
果的海關查驗人員，遂私下透過人脈關係與甲接觸，希望甲可以偷
偷放行電子煙，乙並允諾甲於事成之後，致贈新臺幣 50 萬元酬金給
甲。甲與其配偶丙商量，丙告知近日家中急需用錢，建議甲接受賄
款，以解決家中債務問題。甲、丙商量之後，甲在查驗時放行該批
走私電子煙，然後，乙再將新臺幣 50 萬元賄款裝在紙袋中交給丙。
試問：甲、丙之行為如何論罪？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:06+00:00", "source_pdf_sha1": "b9ed62dd3773", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0805", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與刑法總則", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00360', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-110-b96fcbef', 'sub-aboriginal-10ced7e2-07', NULL, 'essay', '甲購買百萬豪車一輛，因住家沒有停車位，遂將汽車停在自己家門
旁，但豪車車身太大，常將鄰居乙家的大門擋掉一半，影響乙家進
出，乙為此常與甲發生爭執，但甲總是辯稱汽車沒有完全擋住乙家
大門，不知乙在抱怨什麼。乙因為自家進出不方便，看到豪車停放
就很不爽。某日為了洩憤，拿出小刀刺破豪車右前輪胎，正欲繼續
刺破右後輪胎時，甲從自家陽台看見乙在刺輪胎，立刻拿出手槍朝
乙之頭部射擊，防止乙繼續破壞車輛，結果射中乙，竟將乙射死。
試問：甲之行為如何論罪？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:06+00:00", "source_pdf_sha1": "b9ed62dd3773", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0805", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與刑法總則", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00361', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-110-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '有關民主原則，下列敘述何者錯誤？', '["我國憲政體制係採直接民主制", "我國之主權屬於全體國民", "人民行使國家主權的方式，多係透過投票的方式為之", "原則上以多數決定之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:06+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00362', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-110-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '憲法及增修條文關於「軍人」之規定，下列敘述何者錯誤？', '["現役軍人不得兼任文官", "現役軍人應受軍事審判", "國家應對軍人退役後之就學、就業予以保障", "全國陸海空軍應超出黨派"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:06+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00363', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-110-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '依司法院釋字第756號解釋意旨，關於憲法秘密通訊自由，下列敘述何者錯誤？', '["受刑人在監禁期間，人身自由遭受限制，惟其秘密通訊自由等基本權利，仍受憲法之保障", "監獄長官閱讀受刑人發受書信，涉及對秘密通訊自由核心內涵之干預", "監獄長官為確認有無夾帶違禁品而檢查受刑人書信，並不當然影響通訊內容之秘密性", "監獄長官令受刑人刪除書信部分內容後再發出，如以法律或法律具體明確授權之命令定之，即為憲 法所許"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:06+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00364', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-110-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '依司法院大法官解釋，若法律規定國家對宗教之監督僅適用於佛、道教，未對其他宗教為相同之限制， 該法律規定是否合憲？', '["違憲，因為宗教自由乃是不得以法律限制之基本權", "違憲，因為宗教自由之限制乃是內政部之行政保留事項", "違憲，因為違反宗教中立原則與宗教平等原則", "合憲，因為國家對宗教自由得以法律為必要之限制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:06+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00365', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-110-6ed013db', 'sub-aboriginal-10ced7e2-08', NULL, 'single_choice', '關於憲法平等權，下列何者尚非司法院大法官解釋曾闡述之內涵？', '["對相同事物為差別待遇而無正當理由", "所採取分類與規範目的之達成間是否具一定關聯性", "是否以促進社會多元化為規範目的", "對於不同事物未為合理之差別待遇"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:06+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL)
